mapper.select:
SELECT DISTINCT lt.* FROM ledger_txn lt
WHERE lt.user_id = #{userId}


    AND lt.txn_type != 'ADJUST'



    AND lt.txn_type = #{txnType}


    AND lt.trade_date >= #{startDate}


    AND lt.trade_date <= #{endDate}


    AND lt.product_id = #{productId}


    AND EXISTS (
        SELECT 1 FROM ledger_posting lp 
        INNER JOIN accounts a ON lp.account_id = a.id
        WHERE lp.txn_id = lt.txn_id 
        AND (
            lp.account_id = #{accountId}
            OR a.parent_account_id = #{accountId}
        )
    )


    AND EXISTS (
        SELECT 1 FROM ledger_posting lp 
        WHERE lp.txn_id = lt.txn_id 
        AND lp.account_id IN

            #{childId}

    )


    AND lt.note LIKE CONCAT('%', #{note}, '%')

ORDER BY lt.requested_at DESC

    LIMIT #{limit}

        OFFSET #{offset}

SELECT COUNT(DISTINCT lt.txn_id) FROM ledger_txn lt
WHERE lt.user_id = #{userId}


    AND lt.txn_type != 'ADJUST'



    AND lt.txn_type = #{txnType}


    AND lt.trade_date >= #{startDate}


    AND lt.trade_date <= #{endDate}


    AND lt.product_id = #{productId}


    AND EXISTS (
        SELECT 1 FROM ledger_posting lp 
        INNER JOIN accounts a ON lp.account_id = a.id
        WHERE lp.txn_id = lt.txn_id 
        AND (
            lp.account_id = #{accountId}
            OR a.parent_account_id = #{accountId}
        )
    )


    AND EXISTS (
        SELECT 1 FROM ledger_posting lp 
        WHERE lp.txn_id = lt.txn_id 
        AND lp.account_id IN

            #{childId}

    )


    AND lt.note LIKE CONCAT('%', #{note}, '%')
